```class Solution {
    public String minimizeStringValue(String s) {
        int n = s.length();
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '?') {
                for (char c = 'a'; c <= 'z'; c++) {
                    if (!res.toString().contains(String.valueOf(c))) {
                        res.append(c);
                        break;
                    }
                }
            } else {
                res.append(s.charAt(i));
            }
        }
        return res.toString();
    }
}```
